102:
103:	let content: string;
104:	try {
105:		content = await Bun.file(resolvedPath).text();
106:	} catch {
107:		ctx.ui.notify(`Cannot read file: ${resolvedPath}`, "error");
108:		return;
109:	}
110:
111:	// 2. Parse YAML
112:	let def: SwarmDefinition;
113:	try {
114:		def = parseSwarmYaml(content);
115:	} catch (err) {
116:		ctx.ui.notify(`YAML error: ${err instanceof Error ? err.message : String(err)}`, "error");
117:		return;
118:	}
119:
120:	// 3. Validate
121:	const validationErrors = validateSwarmDefinition(def);
122:	if (validationErrors.length > 0) {
123:		ctx.ui.notify(`Validation errors:\n${validationErrors.map(e => `  - ${e}`).join("\n")}`, "error");
124:		return;
125:	}
126:
127:	// 4. Build DAG
128:	const deps = buildDependencyGraph(def);
129:	const cycleNodes = detectCycles(deps);
130:	if (cycleNodes) {
131:		ctx.ui.notify(`Cycle detected in agent dependencies: [${cycleNodes.join(", ")}]`, "error");
132:		return;
133:	}
134:	const waves = buildExecutionWaves(deps);
135:
136:	// 5. Resolve workspace (relative to YAML file location)
137:	const workspace = path.isAbsolute(def.workspace)
138:		? def.workspace
139:		: path.resolve(path.dirname(resolvedPath), def.workspace);
140:
141:	// Ensure workspace exists
142:	await fs.mkdir(workspace, { recursive: true });
143:
144:	// 6. Initialize state tracker
145:	const stateTracker = new StateTracker(workspace, def.name);
146:	await stateTracker.init([...def.agents.keys()], def.targetCount, def.mode);
147:
148:	// 7. Log start
