150:	const waveDesc = waves.map((w, i) => `wave ${i + 1}: [${w.join(", ")}]`).join("; ");
151:	pi.logger.debug("Swarm starting", {
152:		name: def.name,
153:		mode: def.mode,
154:		agents: agentList,
155:		waves: waveDesc,
156:		workspace,
157:	});
158:
159:	ctx.ui.notify(
160:		`Starting swarm '${def.name}': ${def.agents.size} agents, ${waves.length} waves, ${def.targetCount} iteration(s)`,
161:		"info",
162:	);
163:
164:	// 8. Set up progress widget
165:	const widgetKey = `swarm-${def.name}`;
166:	const updateWidget = () => {
167:		const lines = renderSwarmProgress(stateTracker.state);
168:		ctx.ui.setWidget(widgetKey, lines);
169:	};
170:	updateWidget();
171:
172:	// 9. Run pipeline — route by mode
173:	if (def.mode === "loop" && def.loopConfig) {
