317:function findOmpYaml(cwd: string, fileName: string): string | null {
318:	let dir = cwd;
319:	const root = path.parse(dir).root;
320:	while (dir !== root) {
321:		const candidate = path.join(dir, fileName);
322:		try {
323:			if (Bun.file(candidate).size > 0) return candidate;
324:		} catch { /* not found, walk up */ }
325:		const parent = path.dirname(dir);
326:		if (parent === dir) break;
327:		dir = parent;
328:	}
329:	return null;
330:}
